parameters.jsCode:
const aiResponse = $input.first().json;
const originalData = $('Webhook').first().json.body;

let classification = 'NEUTRAL';
let sentimentScore = 5;
let summary = 'Processing';
let suggestedAction = 'Review';
let priority = 'MEDIUM';

try {
  const content = aiResponse.choices[0].message.content;
  const cleanContent = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleanContent);
  classification = parsed.classification || 'NEUTRAL';
  sentimentScore = parsed.sentimentScore || 5;
  summary = parsed.summary || 'No summary';
  suggestedAction = parsed.suggestedAction || 'No action';
  priority = parsed.priority || 'MEDIUM';
} catch (error) {
  const satisfaction = parseInt(originalData.satisfactionLevel) || 3;
  if (satisfaction <= 2) {
    classification = 'NEGATIVE';
    sentimentScore = satisfaction * 2;
    priority = 'HIGH';
    summary = 'Negative feedback';
  } else if (satisfaction >= 4) {
    classification = 'POSITIVE';
    sentimentScore = satisfaction * 2;
    priority = 'LOW';
    summary = 'Positive feedback';
  }
}

return {
  json: {
    fullName: originalData.fullName || '',
    email: originalData.email || '',
    phone: originalData.phone || '',
    feedbackContent: originalData.feedbackContent || '',
    satisfactionLevel: originalData.satisfactionLevel || 3,
    feedbackType: originalData.feedbackType || '',
    classification: classification,
    sentimentScore: sentimentScore,
    summary: summary,
    suggestedAction: suggestedAction,
    priority: priority
  }
};

